   412→impl<I: Interner> Eq for ExistentialProjection<I> {}
   413→
   414→impl<I: Interner> ExistentialProjection<I> {
   415→    pub fn new_from_args(
   416→        interner: I,
   417→        def_id: I::DefId,
   418→        args: I::GenericArgs,
   419→        term: I::Term,
   420→    ) -> ExistentialProjection<I> {
