   620→    for Clause<'tcx>
   621→{
   622→    fn upcast_from(
   623→        from: ty::Binder<'tcx, ty::HostEffectPredicate<'tcx>>,
   624→        tcx: TyCtxt<'tcx>,
   625→    ) -> Self {
   626→        from.map_bound(ty::ClauseKind::HostEffect).upcast(tcx)
   627→    }
   628→}
